      "student_picks_a_game": "Umunyeshure ahitamwo umukino.",
      "quick_assessment": "Isuzuma ryihuta.",
      "daily_routine_templates": "⏱ Ivyitegererezo vy'integuro ya buri musi",
      "pre_built_sequences_of_activities_that": "Inkurikirane z'ibikorwa zubatswe imbere zihuye n'ibice vy'igihe bisanzwe (iminota 10, iminota 30, iminota 45). Hitamwo kimwe hanyuma ukurikire.",
      "identify_fractions_2": "Menya ibice",
      "equivalent_fractions_3": "Ibice bingana",
      "compare_fractions": "Gereranya ibice",
