      "pulmonary_veins": "Imitsi ya Pulmonary",
      "freshly_oxygenated_blood_returns_to_th": "Amaraso amaze kubona ogisijeni asubira ku mutima binyuze mu mitsi ine ya pulmonary.",
      "left_atrium": "Atrium y'Ibumoso",
      "the_four_pulmonary_veins_empty_oxygena": "Imitsi ine ya pulmonary isuka amaraso afite ogisijeni mu atrium y'ibumoso, yuzura hanyuma ikayisunika binyuze muri valve ya mitral.",
      "left_ventricle": "Ventricle y'Ibumoso",
      "blood_passes_through_the_mitral_valve_": "Amaraso anyura muri valve ya mitral yinjira mu ventricle y'ibumoso ifite imitsi, icumba gikomeye kurusha ibindi c'umutima.",
      "aorta_2": "Aorta",
      "the_left_ventricle_powerfully_ejects_b": "Ventricle y'ibumoso isohora amaraso ku mbaraga binyuze muri valve ya aorta muri aorta, umuhanda munini w'umubiri.",
      "body_tissues": "Ingirangingo z'Umubiri",
      "arteries_branch_into_arterioles_and_ca": "Imitsi igabanyamo arterioles na capillaries aho O2 n'intungamubiri bitangwa naho CO2/imyanda bikusanywa.",
      "venous_return": "Isubira ry'Umutsi",
      "deoxygenated_blood_returns_through_ven": "Amaraso adafite ogisijeni asubira binyuze muri venules n'imitsi, afashijwe na pompe z'imitsi na valve, kugeza ku atrium y'iburyo.",
      "path_of_air": "Inzira y'Umwuka",
      "trace_the_journey_of_a_breath_of_air_f": "Kurikira urugendo rw'umwuka wo guhumeka uhereye ku izuru kugeza kuri alveoli no gusubira.",
      "nasal_cavity_2": "Umwobo w'Izuru",
      "air_enters_through_the_nostrils_and_is": "Umwuka winjira binyuze mu mwenge w'izuru maze ushushwa, ukanywebwa amazi, ukayungururwa binyuze mu ruhu rw'imyanda na turbinates.",
      "pharynx_2": "Umuhogo",
      "air_passes_through_the_nasopharynx_and": "Umwuka unyura muri nasopharynx na oropharynx, inzira isangiwe n'inzira y'ibiryo.",
      "larynx": "Larynx",
      "air_crosses_the_vocal_cords_in_the_voi": "Umwuka wambuka imiringoti y'ijwi mu gasanduku k'ijwi. Epiglottis irinda ibiryo kwinjira mu nzira y'umwuka.",
      "trachea_2": "Umuyoboro w'Umwuka",
      "the_trachea_windpipe_is_reinforced_by_": "Umuyoboro w'umwuka ukomezwa n'impeta za cartilage zifite ishusho rya C. Cilia zimura mucus hejuru kugira ngo zifate imyanda.",
      "bronchi": "Bronchi",
      "the_trachea_splits_into_left_and_right": "Umuyoboro w'umwuka ugabanyamo bronchi nkuru z'ibumoso n'iz'iburyo, buri imwe yinjira mu ihaha rimwe. Zigabanyamo bronchioles nto.",
      "alveoli_2": "Alveoli",
      "300_million_grape_like_sacs_where_gas_": "Utubuto miliyoni 300 tumeze nk'inzabibu aho guhererekanya gaze biba. O2 ikwira mu maraso; CO2 ikwira hanze. Ubuso bungana n'ikibuga ca tennis.",
      "exhalation": "Gusohora Umwuka",
      "the_diaphragm_relaxes_and_rises_reduci": "Diaphragm iruhuka ikazamuka, igabanya ingano y'ihaha. Umwuka ukungahaye kuri CO2 usunikwa hanze binyuze mu nzira imwe mu buryo bunyuranye.",
      "path_of_food": "Inzira y'Ibiryo",
      "follow_a_meal_from_mouth_through_the_e": "Kurikira ifunguro uhereye mu kanwa mu buryo bwose bwo kugogora.",
      "mouth": "Akanwa",
      "teeth_mechanically_break_food_down_sal": "Amenyo amena ibiryo mu buryo bw'imashini. Amylase y'amacandwe itangura kugogora amidon. Ururimi rukora ibiryo bikaba bolus.",
      "pharynx_esophagus": "Umuhogo na Œsophage",
      "swallowing_pushes_the_bolus_past_the_e": "Kumira gusunika bolus inyura ku epiglottis. Imiraba ya péristaltique iyimura hasi ya œsophage ya cm 25 mu masegonda 8 hafi.",
      "stomach_2": "Igifu",
      "gastric_acid_ph_1_5_3_5_and_pepsin_bre": "Acide y'igifu (pH 1.5-3.5) na pepsine bimena poroteyine. Kuvanga bikora chyme mu masaha 2-4.",
      "duodenum": "Duodénum",
      "the_first_25cm_of_the_small_intestine_": "Cm 25 za mbere z'amara mato zakira bile iva ku mwijima/agasabo k'inzura na enzymes ziva ku pancréas.",
      "jejunum_ileum": "Jéjunum na Iléum",
      "most_nutrient_absorption_occurs_here_v": "Kunyunyuza intungamubiri kwinshi biba hano binyuze muri villi na microvilli, vyongera ubuso inshuro 600. Uburebure bwa metero 6-7.",
      "large_intestine_2": "Amara manini",
      "water_and_electrolytes_are_reabsorbed_": "Amazi na electrolytes binyunyuzwa bundi bushasha. Bagiteri z'amara zibora fibre isigaye, zikora vitamine K na B12.",
      "rectum_excretion": "Rectum na Gusohora",
      "waste_is_compacted_and_stored_in_the_r": "Imyanda ikandamizwa ikabikwa muri rectum kugeza igihe co kwituma. Urugendo rwose rufata amasaha 24-72.",
      "path_of_a_nerve_signal": "Inzira y'Ikimenyetso c'Umwakura",
