      "receptor": "Uwakira",
      "a_sensory_receptor_in_the_skin_detects": "Uwakira ivyiyumviro mu ruhu (nko gukoraho ku buso bushushe) amenya intandaro y'ububabare akakora ikimenyetso c'amashanyarazi.",
      "sensory_neuron": "Umwakura w'Ivyiyumviro",
      "the_signal_travels_along_a_sensory_aff": "Ikimenyetso kigenda ku mwakura w'ivyiyumviro (afférent) kugeza ku ruti rw'umugongo ku muvuduko ugera kuri 120 m/s binyuze mu kohereza saltatoire.",
      "spinal_cord_2": "Uruti rw'umugongo",
      "in_the_dorsal_horn_the_sensory_neuron_": "Mu ihembe ryo hepfo, umwakura w'ivyiyumviro ukora synapse na interneuron. Ku baréflexe, ikimenyetso ntikigomba kugera ku bwonko.",
      "interneuron": "Interneuron",
      "the_interneuron_in_the_spinal_gray_mat": "Interneuron mu kintu c'ivu c'uruti rw'umugongo uhuza ikimenyetso ukakigeza ku mwakura wo kwimuka.",
      "motor_neuron": "Umwakura wo Kwimuka",
      "the_motor_efferent_neuron_carries_the_": "Umwakura wo kwimuka (efférent) utwara ikimenyetso c'itegeko uhereye ku ihembe ryo imbere kugeza ku mutsi ugenewe.",
      "effector_muscle": "Ukora (Umutsi)",
      "acetylcholine_released_at_the_neuromus": "Acetylcholine isohorwa aho umwakura n'umutsi bihurira itera guhina kw'umutsi. Ukurura ukuboko kwawe mbere yo kumva ububabare.",
      "brain_awareness": "Kumenya kw'Ubwonko",
