      "four_galaxy_morphologies_spirals_like_": "Imiterere ine ya galagisi. Iz'ibizunguruzi nk'iyacu zerekana amaboko agaragaza aho inyenyeri zikorerwa. Iz'elipsi ni za kera, izitagira imiterere zifite akajagari.",
      "spiral_like_milky_way": "Ikizunguruzi (nka Nzira Nyamata)",
      "barred_spiral": "Ikizunguruzi Gifite Umurongo",
      "elliptical_2": "Ya elipsi",
      "irregular_lmc_like": "Idafite imiterere (nka LMC)",
      "100_billion_stars_typical": "Akenshi inyenyeri ~miliyari 100",
      "rotate": "Zunguruka",
      "telescope_aperture_lab": "🔭 Laboratwari y'Umuryango wa Telesikopi",
      "bigger_aperture_gathers_more_light_res": "Umuryango munini ukusanya urumuri rwinshi + ugaragaza ibintu bito. Kwagura ntibifite akamaro kangana n'uko wiyumvira.",
      "aperture_cm": "Umuryango (cm)",
      "magnification": "Kwagura",
      "aperture_matters_more_than_magnificati": "Umuryango ufite akamaro kurusha kwagura! Objectif nini ikusanya urumuri rwinshi + igaragaza ibintu bito. Kwagura kurenze inshuro ~20 kuri cm y'umuryango bituma bijegajega gusa. Indorerwamo ya m 6.5 ya JWST yiga galagisi zo mu myaka miliyoni magana make ya mbere nyuma ya Big Bang.",
      "atmospheric_layers": "🌫 Inzego z'Ikirere",
      "drag_the_altitude_slider_up_through_ea": "Kurura umurongo w'uburabure uzamuke mu kirere c'Isi. Igitutu kiragabanuka, ubushuhe burahinduka, na shimi ihinduka urwego ku rundi.",
      "troposphere_2": "Troposifeeri",
      "weather_happens_here_temperature_decre": "Ikirere kibera hano. Ubushuhe bugabanuka uko uzamuka.",
      "stratosphere_3": "Stratosifeeri",
      "ozone_layer_absorbs_uv_temperature_inc": "Urwego rwa ozone rufata UV. Ubushuhe bwiyongera uko uzamuka.",
      "mesosphere": "Mezosifeeri",
      "meteors_burn_up_here_coldest_layer_90_": "Ibisasu vyo mu kirere bitwikira hano. Urwego rukonje kurusha izindi (-90°C).",
      "thermosphere_2": "Termosifeeri",
      "iss_orbits_here_400km_aurora_glow_very": "ISS izenguruka hano (400km). Aurora iramurika. Umwuka muke cane ariko ushushe.",
      "exosphere": "Ekizosifeeri",
      "boundary_to_space_air_escapes_to_space": "Umupaka ugana mu kirere. Umwuka usohoka uja mu kirere.",
      "iss_400km": "🛰 ISS (400km)",
      "space": "⭐ Ikirere ⭐",
      "altitude_2": "Uburabure hejuru",
      "phases_of_venus_galileo": "♀ Ivyiciro vya Venus (Galileo)",
      "galileo_s_1610_observations_venus_goes": "Ivyo Galileo yabonye mu 1610: Venus inyura mu vyiciro. Ivyo vyerekanye ko Venus izenguruka Izuba, atari Isi.",
      "earth_9": "Isi",
      "venus_3": "Venus",
      "galileo_s_1610_discovery_venus_has_pha": "Ico Galileo yavumbuye mu 1610: Venus ifite ivyiciro nk'ivy'Ukwezi",
      "orbit_2": "Orbite",
      "in_1610_galileo_observed_venus_through": "Mu 1610 Galileo yaravye Venus muri telesikopi ye abona ko inyura mu vyiciro — nk'Ukwezi. Iki cari ikimenyetso ko Venus izenguruka Izuba, atari Isi. Sisitemu ya Ptolemy ishira Isi hagati ntishobora gusigura Venus yuzuye. Ni ikimenyetso gikomeye c'uko Izuba riri hagati nk'uko Copernicus yabivuze.",
      "magnetic_field_visualizer": "🧲 Umwerekanyi w'Umurima wa Magneti",
      "a_magnetic_field_deflects_solar_wind_p": "Umurima wa magneti wirukana umuyaga w'izuba + urinda ikirere. Mars yabuze vyombi; ni yo mpamvu ari ubutayu.",
      "earth_10": "Isi",
      "magnetic_field_3": "Umurima wa magneti",
      "solar_wind_2": "Umuyaga w'izuba",
      "earth_s_magnetic_field_deflects_most_s": "Umurima wa magneti w'Isi wirukana umuyaga mwinshi w'izuba, ukarinda ikirere + ubuzima. Mars yabuze umurima wayo wa magneti mu myaka ~miliyari 4 ishize maze ibura ikirere cayo buhoro. Jupiter ifite umurima ukomeye kurusha iyindi muri sisitemu y'izuba.",
      "solar_system_scale": "📐 Igipimo ca Sisitemu y'Izuba",
      "switch_between_size_and_distance_views": "Hindura hagati y'iraba ry'ubunini n'iry'intera. Vyombi ntibishobora kwerekanwa ku gipimo icarimwe — ni ko ikirere kiri ubusa koko.",
      "mercury_4": "Mercury",
      "venus_4": "Venus",
      "earth_11": "Isi",
      "mars_5": "Mars",
      "jupiter_5": "Jupiter",
      "saturn_2": "Saturn",
      "uranus_2": "Uranus",
      "neptune_3": "Neptune",
      "true_scales_are_hard_to_show_simultane": "Ni bigoye kwerekana ibipimo nyavyo icarimwe. Iyo Isi iba ari akashaza, Izuba ryari kuba umupira w'inyanja uri ibirenge 200 uvuye aho. Iyo intera ziri ku gipimo, imibumbe ihinduka ududomo tutagaragara. Ibishushanyo vyinshi birahuza.",
      "lunar_lander_mini_game": "🛬 Umukino wo Kugwa ku Kwezi",
      "thrust_to_slow_your_descent_land_softe": "Koresha imbaraga zo gutindisha kumanuka kwawe. Gwa buhoro kurusha 2.5 m/s canke uzavunika. Raba lisansi — ntihagije yo guhagarara mu kirere.",
      "landing_pad": "Ikibuga co kugwaho",
      "thrust": "🔥 Imbaraga",
      "fall_tick": "⏬ Kugwa (tick)",
      "apollo_11_nearly_ran_out_of_fuel_durin": "Apollo 11 yenda kubura lisansi mu gihe co kumanuka ku Kwezi. Neil Armstrong yafashe ubuyobozi mu ntoki asimbura ubuyobozi bw'ikoranabuhanga kugira ngo ashake ahantu horoshe ho kugwa. Bageze hasi hasigaye ~amasegonda 25 ya lisansi.",
      "light_year_walker": "⏱ Umugenzi w'Umwaka-Rumuri",
      "pick_a_destination_see_how_long_light_": "Toranya aho ugana + urabe igihe urumuri rufata ngo rugerayo. Hanze ya sisitemu y'izuba, intera ziba nini bitangaje.",
      "moon_3": "Ukwezi",
      "384_400_km": "384,400 km",
      "150_million_km": "miliyoni 150 za km",
      "mars_closest": "Mars (iri hafi)",
